"""
MKT Original Commentary — Judges chapters 7–8
Run: python3 scripts/zc-original-judges-7-8.py

Source data used:
- data/interlinear/judges.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/judges.json

Key decisions in this range:
- "Jerubbaal" retained as parenthetical explanation (yārubba'al = "Let Baal contend")
- shōpār rendered "trumpet" throughout (ram's horn = military/liturgical signal)
- YHWH as divine name throughout
- 8:22-23 kingship offer/refusal is the theological pivot of the Gideon narrative
- ephod in 8:27 treated as free-standing cultic object, not garment
- Baal-berith: "Lord of the covenant" = Canaanite deity at Shechem, distinct from YHWH's covenant
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JUDGES = {
  "7": {
    "1": '<p><strong>Jerubbaal (that is, Gideon)</strong> — the narrator supplies both names at the chapter opening. <em>Yārubba\'al</em> ("Let Baal contend") is the name Joash coined after Gideon tore down the Baal altar (6:32): it declares that Baal has no power to avenge himself. The spring of Harod — <em>ʿēn Ḥarōd</em> — means "spring of trembling," possibly foreshadowing the fear test that follows.</p>',
    "2": '<p><strong>"The people with you are too many for me to give Midian into their hands, lest Israel boast"</strong> — the Hebrew verb is <em>yitpā\'ēr</em> (from <em>pā\'ar</em>: boast, glorify). YHWH\'s stated concern is theological: if Israel wins by force of numbers, the narrative credit shifts from YHWH to human strength. This principle — that divine power is displayed through human weakness — is structurally identical to Paul\'s argument in 1 Cor 1:27–29 that God chose the foolish and weak "so that no human being might boast before God."</p>',
    "3": '<p><strong>"Whoever is fearful and trembling, let him turn back"</strong> — this applies the military exemption of Deut 20:8 ("Is there any man who is fearful and fainthearted? Let him go back to his house"). The departure of 22,000 of the 32,000 (68%) is not a failure of faith but obedience to Torah. The remaining 10,000 are still, as YHWH says (v4), "too many."</p>',
    "4": '<p><strong>"I will test them for you there"</strong> — the Hebrew <em>ʾeṣrᵊpennū lᵊkā</em> uses the verb <em>ṣārap</em> (refine, test — as metal is tested by fire; cf. Ps 12:6; 66:10). YHWH performs a refining, not merely a selection. The water test is a divine winnowing of the army down to the divinely purposed number.</p>',
    "5": '<p><strong>"Set apart everyone who laps…like a dog"</strong> — the verb <em>lāqaq</em> (to lap) is onomatopoeic and appears only here and v6 in the Hebrew Bible. Two postures: lapping with the tongue cupped by the hand (maintaining visual alertness) vs. kneeling on both knees (vulnerable, head down). The 300 lappers are not the more vigilant group — the point is simply that YHWH chose an arbitrary-looking minority to emphasize that the victory is his.</p>',
    "6": '<p><strong>Three hundred men…cupping water with their hands</strong> — the exact figure: 300 out of 10,000 (3%). The absurdity is deliberate: the ratio makes any natural military explanation impossible. The Hebrew <em>mᵊlaqᵊqîm bᵊyādām ʾel-pîhem</em> (lapping with their hand to their mouth) reinforces that the hand, not the mouth, is the active agent — fitting for a victory where human hands will be mere instruments.</p>',
    "7": '<p><strong>"With the three hundred men who lapped I will save you"</strong> — <em>wᵊhôšaʿtî ʾetkhem</em>: I will save you (the verb is <em>yāšaʿ</em>, the same root as Joshua/Jesus). YHWH is the subject; Gideon and the three hundred are instruments. The divine economy of weakness operates here: the fewer the human resources, the more visible the divine agency.</p>',
    "8": '<p><strong>The three hundred took the provisions and trumpets</strong> — <em>šôpārôt</em> (ram\'s horns) become the primary weapon of the battle plan. The word for provisions is <em>ṣēdāh</em> (what one takes for a journey; food supply). Gideon sends 9,700 home while retaining 300 — the ratio of 32:1. The camp of Midian lay below him "in the valley" — topographic advantage noted as the stage is set.</p>',
    "9": '<p><strong>"Arise, go down against the camp, for I have given it into your hand"</strong> — divine prophetic perfect: the victory is stated as already accomplished (<em>nᵊtattî</em>, I have given). The nighttime oracle follows the pattern of Jacob at night (Gen 28), Moses at the burning bush, and later the vision accounts — YHWH breaking into human consciousness at night to commission a mission.</p>',
    "10": '<p><strong>"But if you are afraid to go down"</strong> — the conditional acknowledges the possibility of fear. YHWH does not demand bravado; he accommodates weakness. The servant Purah (<em>Pūrāh</em>, possibly "branch" or "fruitful bough") is mentioned only here and v11 — an incidental detail that marks the account as historically specific.</p>',
    "11": '<p><strong>"Your hands will be strengthened"</strong> — <em>wᵊḥāzᵊqū yādêkā</em> (and your hands will be strong). The idiom "strengthened hands" appears repeatedly in OT military contexts (Ezek 22:14; 2 Sam 2:7) as the standard expression for courage and capability. YHWH offers intelligence before requiring action: "hear what they say, and afterward go down."</p>',
    "12": '<p><strong>"Like locusts in abundance…as numerous as the sand"</strong> — two standard OT hyperboles for uncountable numbers. <em>ḥāgāb lārōb</em> (locusts in multitude) is the same image the prophets use for invading armies (Joel 1:4; Nah 3:15). The deliberate contrast: 300 Israelites vs. an innumerable host. The narrator sets up the miracle by making the numerical disparity overwhelming.</p>',
    "13": '<p><strong>"A loaf of barley bread came tumbling into the camp of Midian"</strong> — <em>ṣᵊlîl lechem śᵊʿōrîm</em>: a rounded (perhaps stale or heavy) loaf of barley bread. Barley (<em>śᵊʿōrîm</em>) was the food of the poor — wheat was preferred; barley was animal fodder or the food of those who could not afford better (cf. John 6:9, the five barley loaves). The dream symbolizes a despised, humble thing overthrowing what seemed indestructible.</p>',
    "14": '<p><strong>"This is nothing other than the sword of Gideon the son of Joash"</strong> — a Midianite soldier interprets his own side\'s nightmare. The irony is striking: YHWH uses the enemy\'s dream to confirm his own commission to Gideon. <em>ḥereb Gidʿōn</em> (the sword of Gideon) — the Midianite interpreter has already collapsed the victory into a single name. "God has given into his hand" uses the divine name <em>Elohim</em>, not YHWH — appropriate in the mouth of a Gentile.</p>',
    "15": '<p><strong>He worshiped. And he returned</strong> — <em>wayyishtaḥū</em> is the standard verb for full prostration in worship (the same verb used for Abraham, Moses, Joshua before YHWH or his messenger). Before giving any orders, Gideon worships. The sequence — receive the divine oracle, worship first, act second — is the pattern of biblical faith. His announcement to the troops ("Arise, for YHWH has given the host of Midian into your hand") echoes the divine word of v9 almost verbatim.</p>',
    "16": '<p><strong>Three companies; a trumpet in every man\'s hand, along with empty jars, with torches inside</strong> — <em>šôpārôt</em> (ram\'s horn trumpets) + <em>kaddîm</em> (jars/pitchers) + <em>lappidîm</em> (torches/flames). The tactical logic: three simultaneous blasts from three directions will sound like a much larger army; smashing 300 jars simultaneously releases sudden blazing light in the dark. The torches are hidden inside the jars until the critical moment.</p>',
    "17": '<p><strong>"Watch me and do likewise"</strong> — <em>ûrᵊ\'îtem kᵊ\'ăšer ʾănî ʿōśeh wᵊken ta\'ăśū</em>: a verbatim command to imitate. The judge acts first and his men follow — the pattern of exemplary leadership. The specific command structure (Gideon acts, three companies follow simultaneously) requires extraordinary coordination for a pre-signal era battle.</p>',
    "18": '<p><strong>"For the LORD and for Gideon!"</strong> — <em>laYHWH ûlᵊGidʿōn</em>: the battle cry pairs the divine name with the judge\'s name. This double invocation is unusual; in most holy war texts YHWH alone is invoked. Gideon\'s name alongside YHWH\'s reflects his role as YHWH\'s designated agent — but the order matters: YHWH first, Gideon second.</p>',
    "19": '<p><strong>"At the beginning of the middle watch"</strong> — the middle watch (second of three; ca. 10 p.m.–2 a.m.) was when the first watch guards had just been relieved and the camp was most disoriented. The timing is tactically precise. <em>wᵊhāqēm hēqîmū ʾet-haššōmᵊrîm</em> — they had just posted the guards: the moment of maximum disorganization in a rotating watch system.</p>',
    "20": '<p><strong>Torches in their left hands, trumpets in their right hands to blow</strong> — the tactical arrangement means no Israelite hand holds a sword: the weapons are light and noise. The cry <em>ḥereb laYHWH ûlᵊGidʿōn</em> ("A sword for the LORD and for Gideon!") declares a sword they do not wield — YHWH is the swordsman.</p>',
    "21": '<p><strong>"All the host ran; they cried out and fled"</strong> — <em>wayyārāṣ kol-hammaḥăneh wayyāriʿū wayyānūsū</em>: the three verbs describe progressive disintegration — ran, cried out, fled. "Every man stood in his place" (<em>ʾîš taḥtāyw</em>, each man under him) — the 300 Israelites hold their positions while the enemy self-destructs. The contrast is between Israelite stillness and Midianite panic.</p>',
    "22": '<p><strong>"YHWH set every man\'s sword against his fellow"</strong> — <em>wayyāśem YHWH ʾēt ḥereb ʾîš bᵊrēʿēhū</em>: YHWH is the grammatical subject; the panic-induced friendly fire is a direct divine act. The same pattern appears at Jehoshaphat\'s battle (2 Chr 20:23) and anticipates YHWH\'s eschatological wars (Zech 14:13). The flight route (Beth-shittah → Zererah → Abel-meholah → Tabbath) traces a real geography of retreat.</p>',
    "23": '<p><strong>The men of Israel were called out from Naphtali, Asher, and all Manasseh</strong> — those who were dismissed in v3 are now summoned to pursue the fleeing enemy. The 300 who fought are joined by the many in the mopping-up phase: the decisive blow required few; the complete victory requires the many. This double-phase appears again in 8:1–3 when Ephraim complains about being left out of the main battle.</p>',
    "24": '<p><strong>"Come down against the Midianites and hold the waters"</strong> — <em>lipdū ʾet-hammayim</em> (seize the waters): cutting off retreat by controlling the water crossings, a standard ANE military tactic. Ephraim\'s role in the pursuit (capturing Oreb and Zeeb, v25) is theologically significant — the tribe that would later complain (8:1) was actually given the decisive honor of capturing the princes.</p>',
    "25": '<p><strong>Oreb ("Raven") and Zeeb ("Wolf")</strong> — the names carry symbolic weight: predatory animals as names for enemy leaders. Their execution locations — <em>ṣūr Ōrēb</em> (Rock of Oreb) and <em>yeqeb Zēʾēb</em> (Winepress of Zeeb) — become permanent landmarks referenced in Ps 83:11 and Isa 10:26, where they become the paradigm of YHWH\'s defeat of Israel\'s enemies. The heads brought to Gideon "beyond the Jordan" confirm the completion of the rout.</p>'
  },
  "8": {
    "1": '<p><strong>"What is this that you have done to us, not to call us when you went to fight?"</strong> — tribal honor in the ANE required being summoned to significant battles; exclusion was an insult (<em>ḥerpāh</em>, reproach/shame, is the implied register). Ephraim was the dominant tribe in central Canaan and expected primacy. Their complaint is fierce (<em>wayyārîbūn ʾittô bᵊḥāzāqāh</em>, they quarreled with him sharply) — the verb <em>rîb</em> is the word for legal disputation and covenant controversy.</p>',
    "2": '<p><strong>"Is not the gleaning of Ephraim better than the vintage of Abiezer?"</strong> — a proverb-style argument. <em>ʿōlelôt ʾEprayim</em> (the gleanings of Ephraim) vs. <em>bᵊṣîr ʾăbîʿezer</em> (the vintage of Abiezer/Gideon\'s clan). Gleaning was what was left after harvest; vintage was the main crop. Gideon inverts the normal valuation: Ephraim\'s secondary role (capturing the princes) was worth more than his own primary campaign. Diplomatic self-deprecation that deflects the tribal grievance.</p>',
    "3": '<p><strong>"What was I able to do compared to you? Then their anger subsided"</strong> — <em>wā\'āpēr rûḥām mēʿālāyw</em>: their spirit relaxed/was assuaged toward him. The root <em>rāpāh</em> (relax, be slack) describes the deflation of anger. Gideon\'s rhetorical skill succeeds where force would have inflamed. The episode contrasts with Jephthah\'s identical conflict with Ephraim (12:1–6), where refusal to apply diplomatic wisdom leads to civil war.</p>',
    "4": '<p><strong>"Exhausted yet still pursuing"</strong> — <em>ʿāyēp wᵊhēm rōdᵊpîm</em>: faint/exhausted (ʿāyēp) while (wᵊhēm, "yet they are") pursuing. The participle <em>rōdᵊpîm</em> marks ongoing action: they have not stopped despite the physical cost. The juxtaposition — weakness and persistence — echoes the "faint yet pursuing" spirituality of Isaiah 40:31 ("those who hope in YHWH will renew their strength").</p>',
    "5": '<p><strong>"I am pursuing Zebah and Zalmunna, the kings of Midian"</strong> — the two kings\' names: <em>Zebaḥ</em> ("sacrifice/slaughter") and <em>Ṣalmunnāʾ</em> ("image withheld" or "shadow of protection denied"). Gideon makes his case to Succoth on the basis of ongoing holy war: the pursuit of the kings is not yet complete and feeding the troops is an act of covenant solidarity.</p>',
    "6": '<p><strong>"Are the hands of Zebah and Zalmunna already in your hand?"</strong> — <em>hakap Zebaḥ wᵊṢalmunnāʾ ʿattāh bᵊyādekā</em>: an ironic rhetorical question. "Hand" (<em>yād</em>) appears twice: "hands of the kings" vs. "in your hand." The officials of Succoth demand proof of victory before committing provisions — a calculus of self-interest over covenant solidarity. They are Israelites who refuse to help fellow Israelites.</p>',
    "7": '<p><strong>"I will flail your flesh with the thorns of the wilderness and with briers"</strong> — <em>dōš ʾet-bᵊśarkem</em>: the verb <em>dāš</em> means to thresh (as grain is threshed); here applied to human bodies. The punishment fits the refusal: those who withheld bread from weary fighters will themselves be threshed. The specific mention of <em>qōṣê hammidbār</em> (thorns of the wilderness) connects the punishment to the very landscape Gideon traversed.</p>',
    "8": '<p><strong>Penuel answered him just as Succoth had</strong> — the doubling of the refusal (two towns, same response) constitutes a legal pattern in ANE contexts: a sin established by two witnesses. It also marks the theological collapse of Transjordanian Israel\'s solidarity with YHWH\'s ongoing war — two communities choosing self-preservation over covenant loyalty.</p>',
    "9": '<p><strong>"When I return in peace, I will break down this tower"</strong> — Gideon\'s announcement creates a narrative promise that the reader knows will be fulfilled (8:17). The tower (<em>migdāl</em>) was the central fortification of Penuel — its destruction would be a permanent public humiliation. The word "in peace" (<em>bᵊšālôm</em>) is ironic: Gideon plans violent retribution framed as the completion of peaceful return.</p>',
    "10": '<p><strong>"About fifteen thousand men — all who were left"</strong> — the narrator provides the arithmetic: 120,000 swords had fallen; 15,000 remained. A 13:1 kill ratio in the battle. The number 120,000 is conventionally large in ANE military narratives; the 15,000 is the routed remnant. The geographical note (Karkor) places the final engagement deep in Transjordanian territory, far east of Israel\'s settled land.</p>',
    "11": '<p><strong>"The army was off guard"</strong> — <em>kî hammaḥăneh hāyāh beṭaḥ</em>: the camp was trusting/secure (<em>beṭaḥ</em>, the same word used for a city dwelling in safety). The element of surprise — Gideon goes by the route of the tent-dwellers (nomadic path) that the Midianites did not expect to be used — is the final military stroke. The defeat of Zebah and Zalmunna mirrors the defeat of Oreb and Zeeb: YHWH\'s holy war is complete.</p>',
    "12": '<p><strong>"He pursued them and captured the two kings"</strong> — <em>wayyirdōp wayyilkōd ʾet-šᵊnê malkê Midyān</em>: pursue and capture (both in perfect consecutive, marking completed action). "Throwing the whole army into a panic" (<em>wayyaḥrad kol-hammaḥăneh</em>, the whole camp trembled/was thrown into confusion) — the same divine panic (ḥarrādāh) that YHWH sent earlier on Gideon\'s enemies.</p>',
    "13": '<p><strong>Gideon returned "from battle by the ascent of Heres"</strong> — a geographical note fixing the precise return route. <em>Ḥeres</em> may mean "sun" — a possible solar toponym. The brief notice of return after battle is a standard ANE victory formula: the campaign is complete, the king/judge returns victorious.</p>',
    "14": '<p><strong>"He captured a young man of Succoth and questioned him. The young man wrote down for him…seventy-seven men"</strong> — one of the earliest references to writing (<em>wayyiktōb</em>, and he wrote) by a private individual in Judges. That a "young man" (<em>naʿar</em>) could write the names of 77 civic leaders suggests a surprising level of literacy in pre-monarchic Transjordanian Israel. The seventy-seven matches a conventional number in Ugaritic texts for divine or royal councils.</p>',
    "15": '<p><strong>"Behold Zebah and Zalmunna, about whom you taunted me"</strong> — the word "taunted" is <em>ḥērap</em> (to reproach/defame), the strongest word for public shaming. Gideon keeps his promise: the proof of victory is presented to the very men who demanded it. The legal procedure of confronting accusers with evidence is precise.</p>',
    "16": '<p><strong>"He taught the men of Succoth a lesson"</strong> — <em>wayyōdaʿ ʾet-ʾanšê Sūkkôt</em>: literally "he made the men of Succoth to know." The Hebrew <em>yādaʿ</em> (to know) in a causative form — to teach someone to know through painful experience. The thorns and briers used for threshing flesh are literally what Gideon had promised in v7.</p>',
    "17": '<p><strong>He tore down the tower of Penuel and killed the men of the city</strong> — the destruction is exactly as promised in v9. No additional narrative comment is made; the action speaks. The killing of the men of Penuel is more severe than the punishment of Succoth (thorns). Penuel had a strategic tower and may have been a more fortified town; its refusal to help was a more deliberate act of defiance.</p>',
    "18": '<p><strong>"They were like you — every one of them had the bearing of a king\'s son"</strong> — <em>kᵊtō\'ar bᵊnê hammelek</em> (like the appearance of the sons of a king). The enemy kings\' observation identifies Gideon\'s brothers as men of noble bearing. The revelation — Gideon\'s brothers were killed at Tabor — transforms the military execution into a blood-vengeance obligation (<em>gō\'ēl haddām</em>). What was a holy war now also carries a personal dimension.</p>',
    "19": '<p><strong>"As the LORD lives, if you had let them live, I would not kill you"</strong> — the oath formula <em>ḥay YHWH</em> (as YHWH lives) binds Gideon\'s statement. The conditional confirms that the execution of Zebah and Zalmunna is blood-vengeance for the murder of his full brothers (<em>bᵊnê ʾimmî</em>, sons of my mother). The same-mother qualification marks them as full brothers vs. half-brothers — the distinction matters in ANE inheritance and honor law.</p>',
    "20": '<p><strong>"Rise and kill them!" But the young man did not draw his sword, for he was afraid</strong> — Jether, as firstborn son, would gain honor by executing the kings. His hesitation (<em>yārēʾ kî ʿôd naʿar</em>, he was afraid because he was still a youth) is a narrative foil: the young man is unwilling to take the honor. Zebah and Zalmunna\'s response in v21 shows they understand the honor system — they prefer to die by Gideon\'s hand, not a boy\'s.</p>',
    "21": '<p><strong>"For as the man is, so is his strength" — Gideon rose and killed them</strong> — the proverb (<em>kî kā\'îš gᵊbūrātô</em>: as the man, so is his strength) is the enemy kings\' appeal to warrior honor: they want to die at the hand of a worthy opponent. Gideon takes the <em>śahᵃrōnîm</em> (crescent ornaments — lunar amulets) from their camels\' necks — cultic trophies that become the material for the ill-fated ephod (v27).</p>',
    "22": '<p><strong>"Rule over us — you and your son and your grandson"</strong> — the offer of hereditary kingship (<em>ûbinkā ûben-binkā</em>) makes this a formal dynastic proposal. The basis: "for you have saved us from the hand of Midian" (<em>kî hôšaʿtānū</em>: the verb <em>yāšaʿ</em> again). The people\'s offer is not wrong in content — Gideon has indeed delivered them — but in locating the right of rule in the deliverer rather than in YHWH.</p>',
    "23": '<p><strong>"I will not rule over you, and my son will not rule over you; the LORD will rule over you"</strong> — this is the theological center of the Gideon narrative. <em>lō\' ʾemšōl bākem…YHWH yimšōl bākem</em>: the verb <em>māšal</em> (to rule, to have dominion) is the same in both clauses; the transfer is absolute. Gideon correctly identifies the theocratic principle: YHWH is Israel\'s king; the deliverer is his instrument, not a replacement. The tragedy of ch 8-9 is that Gideon enacts kingship in every way except the name — many wives (v30), an ephod-idol (v27), a concubine in Shechem (v31) — and his son Abimelech will take the title explicitly.</p>',
    "24": '<p><strong>"Give me each man an earring from his plunder"</strong> — <em>ʾezmᵊrôt zāhāb</em> (golden earrings). The note that the Midianites were Ishmaelites (<em>kî yiśmᵊʾēlîm hēm</em>) explains the golden earrings — Ishmaelites were known as traders and gold-workers (cf. Gen 37:25-28). The voluntary collection suggests Gideon\'s personal request is an act of charismatic authority rather than legal taxation.</p>',
    "25": '<p><strong>"We will gladly give them"</strong> — <em>nātôn nittēn</em>: the infinitive absolute construction intensifies the willingness — "we will absolutely give them." The garment spread out (<em>śimla</em>) as a collection vessel is a practical detail that authenticates the scene; it also connects to garments spread before kings (2 Kgs 9:13) — an unconscious royal gesture from the people who just offered Gideon a crown.</p>',
    "26": '<p><strong>Seventeen hundred shekels of gold — besides the crescent ornaments, pendants, and purple garments</strong> — the itemized list: <em>śahᵃrōnîm</em> (crescent moon amulets), <em>nᵊṭîpôt</em> (pendant ornaments), <em>bigdê ha\'argāmān</em> (purple garments of the Midianite kings), <em>hānᵊṭîpôt</em> (necklaces of the camels). The total wealth is enormous; the detail of "purple garments" marks the Midianite kings as royal figures. All of this becomes the raw material for apostasy.</p>',
    "27": '<p><strong>Gideon made an ephod from it and placed it in Ophrah</strong> — an <em>ʾēpôd</em> in its priestly function was a garment worn by the high priest, holding the Urim and Thummim. Here it is a free-standing cultic object placed in a city — functioning as an unauthorized oracle shrine. <em>wayyizᵊnū kol-yiśrā\'ēl ʾaḥărāyw šām</em>: all Israel committed spiritual adultery (<em>zānāh</em>, the standard term for covenant infidelity) after it there. <em>wayhî lᵊGidʿōn ûlᵊbêtô lᵊmôqēš</em>: it became a snare (<em>môqēš</em>) to Gideon and his house — the same word used in Exod 23:33 for idols as a snare.</p>',
    "28": '<p><strong>The land had rest forty years in the days of Gideon</strong> — <em>wayyishtaqeṭ hā\'āreṣ ʾarbaʿîm šānāh</em>: the land rested/was quiet. The forty-year rest is the standard sabbatical period in Judges (Othniel 40 years, Deborah 40 years, here 40 years). Forty years is a generation — one full cycle before apostasy resumes. The rest is YHWH\'s gift; its end with Gideon\'s death confirms that the rest was tied to his person, not to any institutional transformation.</p>',
    "29": '<p><strong>Jerubbaal the son of Joash went and lived in his own house</strong> — the formulaic withdrawal to private life after the deliverer\'s work is done mirrors the pattern of all major judges. "Lived in his own house" (<em>wayyēšeb bᵊbêtô</em>) is also the phrase used for kings who have consolidated power; here it ironically anticipates the household drama of ch 9.</p>',
    "30": '<p><strong>Gideon had seventy sons, his own offspring, for he had many wives</strong> — seventy sons (<em>šibʿîm bānîm yōṣᵊʾê yᵊrēkô</em>, from his own loins) plus a concubine\'s son. The seventy is a loaded number: seventy elders of Israel (Num 11:16), seventy descendants of Jacob (Gen 46:27), seventy nations in Gen 10. The seventy sons will be massacred down to one (Abimelech) in ch 9 — a catastrophic inversion of the founding promise to Abraham\'s numerous descendants.</p>',
    "31": '<p><strong>His concubine who was in Shechem bore him Abimelech</strong> — <em>ʾăbîmelek</em> means "my father is king" — a name whose irony is dense: Gideon refused the title of king (v23) but named his son "my father is king." The concubine\'s Shechemite origin is significant: Shechem was the center of Baal-berith worship (9:4), and Abimelech will leverage his Shechemite half-identity to seize power there. The seed of apostasy is planted in Gideon\'s own household.</p>',
    "32": '<p><strong>Gideon died at a good old age</strong> — <em>ûmāt Gidʿōn ben-Yôʾāš bᵊśêbāh ṭôbāh</em>: the formula "good old age" (<em>śêbāh ṭôbāh</em>) appears for Abraham (Gen 15:15), Ishmael (Gen 25:8), and David\'s officers — it marks a life completed with honor. Buried in the tomb of his father Joash at Ophrah of the Abiezrites: ancestral burial as the final marker of belonging to the covenant community.</p>',
    "33": '<p><strong>"As soon as Gideon died, the people of Israel turned again"</strong> — <em>wayhî ka\'ăšer mēt Gidʿōn wayyāšūbū</em>: the causative connection is immediate and explicit. <em>Baalîm</em> (the plural of Baal) and specifically <em>Baʿal-bᵊrît</em> (Lord of the Covenant) — a Canaanite deity whose name mocks YHWH\'s covenant relationship with Israel by applying the covenant vocabulary (<em>bᵊrît</em>) to a pagan god. This apostasy is located at Shechem, where Abimelech will receive his blood-money from Baal-berith\'s temple (9:4).</p>',
    "34": '<p><strong>"Did not remember the LORD their God, who had delivered them from all their enemies"</strong> — <em>lō\' zākᵊrū</em> (they did not remember): forgetting (<em>šākaḥ</em>) and not-remembering (<em>lō\' zākar</em>) are the root sins of the Deuteronomic covenant. The participle <em>hammôšîʿ</em> (the one who saves/saves them) is a title for YHWH — the same root as the names Joshua/Jesus. Forgetting the Savior is the primary covenant breach.</p>',
    "35": '<p><strong>"They did not show <em>hesed</em> to the family of Jerubbaal"</strong> — <em>wᵊlō\' ʿāśū ḥesed ʿim-bêt Yᵊrubbāʿal</em>: <em>ḥesed</em> (covenant loyalty, steadfast love, faithful kindness) is the central covenant virtue; its failure here is both a social crime (not honoring Gideon\'s family) and a theological one (ḥesed toward YHWH\'s servant mirrors ḥesed toward YHWH). The book closes Gideon\'s narrative with the failure of both vertical ḥesed (v34, forgetting YHWH) and horizontal ḥesed (v35, abandoning Gideon\'s family) — the double collapse of covenant faithfulness.</p>'
  }
}

